import{_ as n,c as i,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Fortgeschritten: Pipelines und interne Mechanismen | AI App Factory Tutorial","description":"Vertiefen Sie Ihr Verständnis des 7-Phasen-Pipelines, des Sisyphus-Schedulers, der Berechtigungs- und Sicherheitsmechanismen sowie der Fehlerbehandlungsstrategien von AI App Factory. Meistern Sie Kontextoptimierung und fortgeschrittene Konfigurationstechniken.","frontmatter":{"title":"Fortgeschritten: Pipelines und interne Mechanismen | AI App Factory Tutorial","sidebarTitle":"Fortgeschritten: Pipelines","subtitle":"Fortgeschritten: Pipelines und interne Mechanismen","description":"Vertiefen Sie Ihr Verständnis des 7-Phasen-Pipelines, des Sisyphus-Schedulers, der Berechtigungs- und Sicherheitsmechanismen sowie der Fehlerbehandlungsstrategien von AI App Factory. Meistern Sie Kontextoptimierung und fortgeschrittene Konfigurationstechniken.","tags":["Pipeline","Scheduler","Berechtigungen und Sicherheit","Fehlerbehandlung"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"de/hyz1992/agent-app-factory/advanced/index.md","filePath":"de/hyz1992/agent-app-factory/advanced/index.md"}'),s={name:"de/hyz1992/agent-app-factory/advanced/index.md"};function l(a,e,h,o,u,d){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="fortgeschritten-pipelines-und-interne-mechanismen" tabindex="-1">Fortgeschritten: Pipelines und interne Mechanismen <a class="header-anchor" href="#fortgeschritten-pipelines-und-interne-mechanismen" aria-label="Permalink to &quot;Fortgeschritten: Pipelines und interne Mechanismen&quot;">​</a></h1><p>Dieses Kapitel bietet eine eingehende Erklärung der Kernmechanismen und fortgeschrittenen Funktionen von AI App Factory, einschließlich der detaillierten Arbeitsweise des 7-Phasen-Pipelines, der Scheduling-Strategien des Sisyphus-Schedulers, der Berechtigungs- und Sicherheitsmechanismen, der Fehlerbehandlungsstrategien sowie der Optimierung des Kontexts zur Senkung der Token-Kosten.</p><div class="warning custom-block"><p class="custom-block-title">Voraussetzungen</p><p>Vergewissern Sie sich vor dem Studium dieses Kapitels, dass Sie folgende Schritte abgeschlossen haben:</p><ul><li><a href="./../../start/getting-started/">Schnellstart</a> und <a href="./../../start/installation/">Installation und Konfiguration</a></li><li><a href="./../../start/pipeline-overview/">7-Phasen-Pipeline-Übersicht</a></li><li><a href="./../../platforms/claude-code/">Plattformintegration</a> Konfiguration</li></ul></div><h2 id="kapitelinhalt" tabindex="-1">Kapitelinhalt <a class="header-anchor" href="#kapitelinhalt" aria-label="Permalink to &quot;Kapitelinhalt&quot;">​</a></h2><p>Dieses Kapitel behandelt folgende Themen:</p><h3 id="detaillierte-7-phasen-pipeline" tabindex="-1">Detaillierte 7-Phasen-Pipeline <a class="header-anchor" href="#detaillierte-7-phasen-pipeline" aria-label="Permalink to &quot;Detaillierte 7-Phasen-Pipeline&quot;">​</a></h3><ul><li><p><strong><a href="./stage-bootstrap/">Phase 1: Bootstrap - Strukturierung von Produktideen</a></strong></p><ul><li>Lernen Sie, wie vage Produktkonzepte in strukturierte Dokumente verwandelt werden</li><li>Verstehen Sie das Ein- und Ausgabeformat des Bootstrap-Agenten</li></ul></li><li><p><strong><a href="./stage-prd/">Phase 2: PRD - Erstellung von Produktanforderungsdokumenten</a></strong></p><ul><li>Generierung eines MVP-PRD mit User Stories, Funktionslisten und Nicht-Zielen</li><li>Beherrschung von Anforderungszerlegung und Priorisierungstechniken</li></ul></li><li><p><strong><a href="./stage-ui/">Phase 3: UI - Interface- und Prototyp-Design</a></strong></p><ul><li>Nutzung der ui-ux-pro-max-Skill für UI-Struktur und vorschaufähige Prototypen</li><li>Verstehen des UI-Design-Prozesses und bewährter Verfahren</li></ul></li><li><p><strong><a href="./stage-tech/">Phase 4: Tech - Technische Architektur-Design</a></strong></p><ul><li>Entwicklung einer minimal durchführbaren technischen Architektur und Prisma-Datenmodells</li><li>Beherrschung von Technologieauswahl und Architekturprinzipien</li></ul></li><li><p><strong><a href="./stage-code/">Phase 5: Code - Generierung ausführbarer Implementierung</a></strong></p><ul><li>Erstellung von Frontend- und Backend-Code, Tests und Konfigurationen basierend auf UI-Schema und Tech-Design</li><li>Verstehen des Code-Generierungsprozesses und Template-Systems</li></ul></li><li><p><strong><a href="./stage-validation/">Phase 6: Validierung - Qualitätssicherung der Implementierung</a></strong></p><ul><li>Überprüfung von Abhängigkeitsinstallation, Typisierung, Prisma-Schema und Codequalität</li><li>Meistern automatisierter Qualitätsprüfungsprozesse</li></ul></li><li><p><strong><a href="./stage-preview/">Phase 7: Preview - Bereitstellungsdokumentation</a></strong></p><ul><li>Erstellung vollständiger Ausführungs- und Bereitstellungsdokumentation</li><li>Integration von CI/CD und Git-Hooks-Konfiguration</li></ul></li></ul><h3 id="interne-mechanismen" tabindex="-1">Interne Mechanismen <a class="header-anchor" href="#interne-mechanismen" aria-label="Permalink to &quot;Interne Mechanismen&quot;">​</a></h3><ul><li><p><strong><a href="./orchestrator/">Sisyphus-Scheduler-Detaillierung</a></strong></p><ul><li>Verstehen Sie, wie der Scheduler Pipelines koordiniert, Status verwaltet und Berechtigungsprüfungen durchführt</li><li>Beherrschung von Scheduling-Strategien und Zustandsautomatenprinzipien</li></ul></li><li><p><strong><a href="./context-optimization/">Kontextoptimierung: Session-basierte Ausführung</a></strong></p><ul><li>Lernen Sie die Nutzung von <code>factory continue</code> zur Token-Effizienz</li><li>Meistern Sie bewährte Verfahren für die Neuerstellung von Sitzungen in jeder Phase</li></ul></li><li><p><strong><a href="./security-permissions/">Berechtigungs- und Sicherheitsmechanismen</a></strong></p><ul><li>Verstehen von Capability-Boundary-Matrizen, Überberechtigungsbehandlung und Sicherheitsprüfungsmechanismen</li><li>Beherrschung von Sicherheitskonfigurationen und Rechtemanagement</li></ul></li><li><p><strong><a href="./failure-handling/">Fehlerbehandlung und Rollback</a></strong></p><ul><li>Erlernen Sie Fehleridentifikation, Wiederholungsmechanismen, Rollback-Strategien und manuelle Interventionsprozesse</li><li>Meistern Sie Fehlerbehebung und Wiederherstellungstechniken</li></ul></li></ul><h2 id="lernpfad-empfehlungen" tabindex="-1">Lernpfad-Empfehlungen <a class="header-anchor" href="#lernpfad-empfehlungen" aria-label="Permalink to &quot;Lernpfad-Empfehlungen&quot;">​</a></h2><h3 id="empfohlene-lernreihenfolge" tabindex="-1">Empfohlene Lernreihenfolge <a class="header-anchor" href="#empfohlene-lernreihenfolge" aria-label="Permalink to &quot;Empfohlene Lernreihenfolge&quot;">​</a></h3><ol><li><p><strong>Absolvieren Sie zuerst die 7-Phasen-Pipeline</strong> (in Reihenfolge)</p><ul><li>Bootstrap → PRD → UI → Tech → Code → Validierung → Preview</li><li>Jede Phase hat klare Eingaben und Ausgaben, das sequenzielle Lernen schafft ein vollständiges Verständnis</li></ul></li><li><p><strong>Lernen Sie anschließend Scheduler und Kontextoptimierung</strong></p><ul><li>Verstehen Sie, wie Sisyphus diese 7 Phasen koordiniert</li><li>Lernen Sie, wie Sie den Kontext optimieren können, um Token-Kosten zu sparen</li></ul></li><li><p><strong>Lernen Sie zuletzt Sicherheit und Fehlerbehandlung</strong></p><ul><li>Meistern Sie Berechtigungsgrenzen und Sicherheitsmechanismen</li><li>Verstehen Sie Fehlerszenarien und Bewältigungsstrategien</li></ul></li></ol><h3 id="lernschwerpunkte-fur-verschiedene-rollen" tabindex="-1">Lernschwerpunkte für verschiedene Rollen <a class="header-anchor" href="#lernschwerpunkte-fur-verschiedene-rollen" aria-label="Permalink to &quot;Lernschwerpunkte für verschiedene Rollen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rolle</th><th>Wichtige Kapitel</th></tr></thead><tbody><tr><td><strong>Entwickler</strong></td><td>Code, Validierung, Tech, Orchestrator</td></tr><tr><td><strong>Produktmanager</strong></td><td>Bootstrap, PRD, UI, Preview</td></tr><tr><td><strong>Technischer Leiter</strong></td><td>Tech, Code, Sicherheit, Fehlerbehandlung</td></tr><tr><td><strong>DevOps-Ingenieur</strong></td><td>Validierung, Preview, Kontextoptimierung</td></tr></tbody></table><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie weiter lernen:</p><ul><li><strong><a href="./../../faq/troubleshooting/">Häufig gestellte Fragen und Fehlerbehebung</a></strong> - Lösung von Problemen bei der tatsächlichen Nutzung</li><li><strong><a href="./../../faq/best-practices/">Bewährte Verfahren</a></strong> - Meistern Sie Techniken für die effiziente Nutzung von Factory</li><li><strong><a href="./../../appendix/cli-commands/">CLI-Befehlsreferenz</a></strong> - Vollständige Befehlsliste anzeigen</li><li><strong><a href="./../../appendix/code-standards/">Codestandards</a></strong> - Verstehen Sie die Standards, die der generierte Code einhalten muss</li></ul><hr><p>💡 <strong>Tipp</strong>: Wenn Sie bei der Nutzung auf Probleme stoßen, konsultieren Sie zuerst das Kapitel <a href="./../../faq/troubleshooting/">Häufig gestellte Fragen und Fehlerbehebung</a>.</p>',19)])])}const p=n(s,[["render",l]]);export{c as __pageData,p as default};
